#include<bits/stdc++.h>
using namespace std;

int main(){
   int t;
   cin>>t;
   while(t--){
    int n;
    cin>>n;
    int H;
    cin>>H;
    int ans = n;
    int h[n];
    for (int i =0;i<n;i++){cin>>h[i];}
    sort(h,h+n);
    bool cases[n+1][H+1];  
    for (int i=0;i<n+1;i++){
        for(int j =0;j<H+1;j++){
            cases[i][j] = false;
        }
    }
    cases[0][0] = true;
    for (int i=n-1;i>=0;i--){
        int t1 = 0;
        for (int j =0;j<i;j++){t1+=h[j];}
        if (i < n-1){
            for (int l=n-1;l>=0;l--){
                for(int m =0;m<H+1-h[i+1];m++){
                    if (cases[l][m]){cases[l+1][m+h[i+1]] = true;} 
                }
            }
        }
        for (int l=0;l<n+1;l++){
                for(int m =0;m<H+1;m++){
                    if (cases[l][m]){
                        int tt = t1+m;
                        if (h[i]*(i+l+1)>(H-tt) && tt<=H && i+l>0){
                            ans = min(ans,i+l);
                        }
                    } 
                }
            }
    }
    cout<<ans<<endl;
   }
}

